import{_ as e,a as t,b as n,c as i,d as l}from"./chunks/编辑配置.T0puvWjh.js";import{_ as d,o as r,c as o,a2 as s}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Menambahkan Telegram Channel","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/upload/telegram.md","filePath":"id-ID/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"id-ID/upload/telegram.md"};function m(c,a,u,k,p,b){return r(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="menambahkan-telegram-channel" tabindex="-1">Menambahkan Telegram Channel <a class="header-anchor" href="#menambahkan-telegram-channel" aria-label="Permalink to &quot;Menambahkan Telegram Channel&quot;">​</a></h1><h2 id="yang-perlu-disiapkan-sebelum-mulai" tabindex="-1">Yang Perlu Disiapkan Sebelum Mulai <a class="header-anchor" href="#yang-perlu-disiapkan-sebelum-mulai" aria-label="Permalink to &quot;Yang Perlu Disiapkan Sebelum Mulai&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Telegram account</td><td>Digunakan untuk membuat bot dan storage channel.</td></tr><tr><td><code>@BotFather</code></td><td>Digunakan untuk membuat Telegram bot.</td></tr><tr><td>Telegram channel</td><td>Tujuan akhir penyimpanan files.</td></tr><tr><td><code>@userinfobot</code></td><td>Digunakan untuk mencari <code>Chat ID</code> channel.</td></tr></tbody></table><h2 id="di-mana-menambahkannya" tabindex="-1">Di Mana Menambahkannya <a class="header-anchor" href="#di-mana-menambahkannya" aria-label="Permalink to &quot;Di Mana Menambahkannya&quot;">​</a></h2><ol><li>Buka System Settings.</li><li>Masuk ke Upload Settings.</li><li>Klik Add Channel di kanan atas.</li><li>Pilih <code>Telegram</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama yang mudah dikenali untuk channel ini, misalnya &quot;Telegram Primary&quot;.</td><td>Required</td></tr><tr><td>Active</td><td>Mengaktifkan atau menonaktifkan channel ini.</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>Token untuk Telegram bot Anda.</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>ID Telegram channel.</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Gunakan hanya jika akses Telegram tidak stabil. Masukkan proxy URL lengkap, termasuk <code>https://</code>.</td><td>Optional</td></tr><tr><td>Remark</td><td>Catatan untuk maintenance di kemudian hari.</td><td>Optional</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="_1-buat-telegram-bot" tabindex="-1">1. Buat Telegram Bot <a class="header-anchor" href="#_1-buat-telegram-bot" aria-label="Permalink to &quot;1. Buat Telegram Bot&quot;">​</a></h3><ol><li>Buka Telegram dan cari <code>@BotFather</code>.</li><li>Buka chat dan klik <code>Start</code>.</li><li>Kirim <code>/newbot</code>.</li><li>Ikuti prompt untuk memasukkan bot display name.</li><li>Ikuti prompt untuk memasukkan bot username. Biasanya username harus diakhiri dengan <code>bot</code>.</li><li>Setelah bot dibuat, <code>@BotFather</code> akan mengembalikan bot token.</li></ol><p>Token ini adalah <code>Bot Token</code> yang perlu dimasukkan ke ImgBed.</p><p><img src="'+e+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-buat-channel" tabindex="-1">2. Buat Channel <a class="header-anchor" href="#_2-buat-channel" aria-label="Permalink to &quot;2. Buat Channel&quot;">​</a></h3><ol><li>Di Telegram, klik New Channel.</li><li>Masukkan channel name.</li><li>Selesaikan pembuatan channel.</li></ol><p>Public dan private channel sama-sama bisa digunakan.</p><p><img src="'+t+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-tambahkan-bot-ke-channel" tabindex="-1">3. Tambahkan Bot ke Channel <a class="header-anchor" href="#_3-tambahkan-bot-ke-channel" aria-label="Permalink to &quot;3. Tambahkan Bot ke Channel&quot;">​</a></h3><ol><li>Buka channel yang baru dibuat.</li><li>Buka channel settings.</li><li>Tambahkan member atau administrator.</li><li>Cari bot username yang Anda buat.</li><li>Tambahkan bot ke channel.</li></ol><p>Agar upload lebih andal, berikan permission administrator kepada bot.</p><p><img src="'+n+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-ambil-channel-id-dengan-user-info-get-id-idbot" tabindex="-1">4. Ambil Channel ID dengan User Info - Get ID - IDbot <a class="header-anchor" href="#_4-ambil-channel-id-dengan-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Ambil Channel ID dengan User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>Cari <code>@userinfobot</code> di Telegram. Display name biasanya <code>User Info - Get ID - IDbot</code>.</li><li>Buka chat dan klik <code>Start</code>.</li><li>Pilih <code>Channel</code> dari opsi yang diberikan bot.</li><li>Di message picker, pilih target channel lalu kirim ke <code>@userinfobot</code>.</li><li>Saat <code>@userinfobot</code> mengembalikan hasil, copy angka yang muncul sebagai <code>Id: -100...</code>.</li></ol><p>Angka yang diawali <code>-100</code> adalah <code>Session ID (Chat ID)</code> yang diperlukan ImgBed.</p><p><img src="'+i+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-isi-telegram-channel-di-imgbed" tabindex="-1">5. Isi Telegram Channel di ImgBed <a class="header-anchor" href="#_5-isi-telegram-channel-di-imgbed" aria-label="Permalink to &quot;5. Isi Telegram Channel di ImgBed&quot;">​</a></h3><p>Kembali ke channel configuration dialog dan isi field sebagai berikut:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Nama channel kustom, misalnya <code>TelegramPrimary</code>.</td></tr><tr><td>Active</td><td>Recommended.</td></tr><tr><td>Bot Token</td><td>Bot token dari <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Angka <code>-100...</code> yang dikembalikan oleh <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Hanya jika perlu, misalnya <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Remark</td><td>Catatan opsional.</td></tr></tbody></table><p>Klik Save setelah selesai.</p><p><img src="'+l+`" alt="Edit the configuration" loading="lazy"></p><h2 id="cara-memeriksa" tabindex="-1">Cara Memeriksa <a class="header-anchor" href="#cara-memeriksa" aria-label="Permalink to &quot;Cara Memeriksa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cara Memeriksa</th></tr></thead><tbody><tr><td>Channel card muncul</td><td>Setelah save, halaman Upload Settings harus menampilkan Telegram channel card.</td></tr><tr><td>Channel bisa diaktifkan</td><td>Active switch seharusnya tetap on.</td></tr><tr><td>Configuration tersimpan</td><td>Detail view harus menunjukkan Bot Token dan Chat ID sudah tersimpan.</td></tr><tr><td>Upload berjalan</td><td>Upload test image dan pastikan muncul di Telegram channel tujuan.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buat bot dengan @BotFather</span></span>
<span class="line"><span>-&gt; Simpan Bot Token</span></span>
<span class="line"><span>-&gt; Buat Telegram channel</span></span>
<span class="line"><span>-&gt; Tambahkan bot ke channel dan beri administrator permissions</span></span>
<span class="line"><span>-&gt; Cari @userinfobot dan pilih Channel</span></span>
<span class="line"><span>-&gt; Forward pesan apa pun dari channel ke @userinfobot</span></span>
<span class="line"><span>-&gt; Copy Id: -100... yang dikembalikan</span></span>
<span class="line"><span>-&gt; Masukkan Bot Token dan Chat ID di ImgBed</span></span>
<span class="line"><span>-&gt; Save dan upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const T=d(h,[["render",m]]);export{y as __pageData,T as default};
